"""
Critic2 Adapter
critic2 量子化学分析工具适配器
"""

from pathlib import Path
from typing import Dict, Any, Optional, List
import re
import shutil
from loguru import logger

from .base_adapter import ExternalAdapter, InputBundle, RunResult, ParsedResult, ExternalResult
from ..bridge_context import BridgeContext
from ..executor import ExecutionResult


class Critic2Adapter(ExternalAdapter):
    """
    critic2 适配器
    
    支持的分析类型：
    - qtaim: QTAIM Bader 分析
    """
    
    DEFAULT_CONFIG = {
        "executable": "critic2",
        "timeout_seconds": 300,
        "working_directory": "bridges/critic2",
        "analysis_type": "qtaim",
        "enable_debug_mode": False,
        "qtaim_options": {
            "max_iter": 100,
            "conv_tol": 1e-5,
        }
    }
    
    def __init__(self, config: Optional[Dict[str, Any]] = None):
        merged_config = {**self.DEFAULT_CONFIG, **(config or {})}
        super().__init__(merged_config)
        
        self.analysis_type = self.config["analysis_type"]
        self.working_dir = Path(self.config["working_directory"])
    
    def prepare_inputs(self, context: BridgeContext) -> InputBundle:
        """
        准备 critic2 输入文件
        
        生成 critic2.in 脚本，使用绝对路径引用 cube 文件
        """
        # 创建工作目录
        work_dir = self.working_dir / context.molecule_id
        work_dir.mkdir(parents=True, exist_ok=True)
        
        input_file = work_dir / "critic2.in"
        output_file = work_dir / "critic2.out"
        xyz_file = work_dir / "molecule.xyz"
        
        # 验证 density cube 存在
        density_cube = Path(context.density_cube_path)
        if not density_cube.exists():
            raise FileNotFoundError(f"Density cube not found: {density_cube}")
        
        # 生成分子 xyz（angstrom）
        self._write_xyz(context, xyz_file)

        # 生成输入脚本
        script_lines = self._generate_script(context, density_cube, xyz_file)
        
        # 写入输入文件
        with open(input_file, 'w') as f:
            f.write('\n'.join(script_lines))
        
        logger.debug(f"Generated critic2 input: {input_file}")
        
        return InputBundle(
            input_file=input_file,
            output_file=output_file,
            working_directory=work_dir,
            auxiliary_files=[density_cube, xyz_file],
            command_args=[str(input_file)],
        )
    
    def _write_xyz(self, context: BridgeContext, xyz_file: Path) -> None:
        """写入 xyz 文件，供 critic2 molecule 语句使用"""
        with open(xyz_file, "w") as f:
            f.write(f"{context.natm}\n")
            f.write(f"{context.molecule_id} generated by FastORCA Critic2Adapter\n")
            for sym, coord in zip(context.atom_symbols, context.atom_coords_angstrom):
                f.write(
                    f"{sym} "
                    f"{float(coord[0]):.10f} "
                    f"{float(coord[1]):.10f} "
                    f"{float(coord[2]):.10f}\n"
                )

    def _generate_script(self, context: BridgeContext, density_cube: Path, xyz_file: Path) -> List[str]:
        """生成 critic2 输入脚本"""
        lines = [
            f"# Critic2 input for {context.molecule_id}",
            f"# Generated by FastORCA Critic2Adapter",
            f"# Analysis type: {self.analysis_type}",
            "",
        ]
        
        if self.analysis_type == "qtaim":
            lines.extend(self._generate_qtaim_script(density_cube, xyz_file))
        else:
            raise ValueError(f"Unknown analysis type: {self.analysis_type}")
        
        return lines
    
    def _generate_qtaim_script(self, density_cube: Path, xyz_file: Path) -> List[str]:
        """生成 QTAIM 分析脚本"""
        lines = [
            f"# Load molecular geometry from cube so molecular cell aligns with grid domain",
            # This avoids non-periodic grid vs molecular-cell mismatch in some critic2 builds.
            f"molecule {density_cube.absolute()}",
            "",
            f"# Load density cube with absolute path",
            # NUMERICAL derivatives can avoid FFT periodic-cell requirement on non-periodic molecular cubes.
            f"load {density_cube.absolute()} numerical id rho",
            "",
            "# Keep integrable set minimal to avoid Laplacian FFT path on non-periodic grids",
            "integrable clear",
            "integrable $rho f name Pop",
            "",
            "# Output atomic properties (Bader integration)",
            "bader",
            "",
        ]
        return lines
    
    def run_external(self, input_bundle: InputBundle) -> RunResult:
        """执行 critic2"""
        # 初始化执行器
        self._init_executor(
            executable=self.config["executable"],
            timeout=self.config["timeout_seconds"],
            cwd=str(input_bundle.working_directory),
        )
        
        # 检查可执行文件
        if not self.executor.check_executable():
            raise FileNotFoundError(f"critic2 executable not found: {self.config['executable']}")
        
        # 执行（兼容性模式）
        # 对部分 critic2 构建，`critic2 input.in` 会直接 STOP 1，
        # 但 `critic2 < input.in` 可稳定运行，因此改为 stdin 喂入脚本。
        with open(input_bundle.input_file, "r") as f:
            script_text = f.read()
        exec_result = self.executor.execute(args=[], input_text=script_text)

        # Fallback: BADER + non-periodic grid 可能触发 FFT periodic-cell 报错。
        # 该场景下自动退化为 YT 算法重试（官方对 grid 场景也推荐 YT）。
        stdout_text = exec_result.stdout or ""
        if (
            exec_result.returncode != 0
            and "ERROR (fft): for FFT operations, the input grid must span the periodic cell" in stdout_text
            and re.search(r"(?im)^\s*bader\s*$", script_text) is not None
        ):
            logger.warning("Critic2 BADER failed due FFT periodic-grid constraint; retrying with YT fallback")
            yt_script_text = re.sub(r"(?im)^\s*bader\s*$", "yt", script_text)
            yt_input_file = input_bundle.working_directory / "critic2_yt_fallback.in"
            with open(yt_input_file, "w") as f:
                f.write(yt_script_text)
            yt_result = self.executor.execute(args=[], input_text=yt_script_text)
            yt_output_file = input_bundle.working_directory / "critic2_yt_fallback.out"
            with open(yt_output_file, "w") as f:
                f.write(yt_result.stdout or "")
                if yt_result.stderr:
                    f.write("\n# STDERR\n")
                    f.write(yt_result.stderr)
            if yt_result.returncode == 0:
                logger.info("Critic2 YT fallback succeeded")
                exec_result = yt_result
            else:
                logger.warning("Critic2 YT fallback still failed; keeping original BADER failure result")
                # Keep both outputs for diagnosis in main output artifact
                combined_stdout = (exec_result.stdout or "")
                combined_stdout += "\n\n# ===== YT FALLBACK OUTPUT =====\n"
                combined_stdout += (yt_result.stdout or "")
                combined_stderr = (exec_result.stderr or "")
                if yt_result.stderr:
                    combined_stderr += ("\n" if combined_stderr else "") + yt_result.stderr
                exec_result = ExecutionResult(
                    returncode=exec_result.returncode,
                    stdout=combined_stdout,
                    stderr=combined_stderr,
                    execution_time_seconds=exec_result.execution_time_seconds + yt_result.execution_time_seconds,
                    command=exec_result.command + " | yt_fallback",
                    timed_out=exec_result.timed_out or yt_result.timed_out,
                )
        
        # 保存输出到文件
        with open(input_bundle.output_file, 'w') as f:
            f.write(exec_result.stdout)
            if exec_result.stderr:
                f.write("\n# STDERR\n")
                f.write(exec_result.stderr)
        
        return RunResult(
            execution_result=exec_result,
            output_files=[input_bundle.output_file],
        )
    
    def parse_outputs(self, run_result: RunResult) -> ParsedResult:
        """
        解析 critic2 输出
        
        解析 QTAIM Bader 电荷和体积
        """
        output_file = run_result.output_files[0]
        
        if not output_file.exists():
            raise FileNotFoundError(f"Output file not found: {output_file}")
        
        with open(output_file, 'r') as f:
            content = f.read()
        
        # 解析 Bader 电荷和体积
        features = self._parse_bader_analysis(content)
        
        # 提取版本信息
        version = self._parse_version(content)
        
        # 检查警告
        warnings = self._extract_warnings(content)
        
        return ParsedResult(
            features=features,
            metadata={
                "tool_version": version,
                "analysis_type": self.analysis_type,
                "output_file_size": len(content),
            },
            warnings=warnings,
        )
    
    def _parse_bader_analysis(self, content: str) -> Dict[str, Any]:
        """
        解析 Bader 分析结果
        
        提取：
        - bader_charges
        - bader_volumes
        - n_bader_volumes (验证用)
        """
        features = {
            "qtaim": {
                "bader_charges": None,
                "bader_populations": None,
                "bader_volumes": None,
                "n_bader_volumes": 0,
                "atomic_integrated_properties": None,
                "metadata": {
                    "atomic_property_parser": "none",
                    "atomic_property_source": None,
                    "atomic_property_header_tokens": None,
                    "atomic_property_header_token_count": 0,
                    "atomic_property_rows_parsed": 0,
                    "atomic_property_pop_column": None,
                    "atomic_property_volume_column": None,
                    "atomic_property_volume_available": False,
                    "atomic_property_parse_note": None,
                    "atomic_property_table_excerpt": [],
                    "atomic_integrated_property_columns": None,
                },
            }
        }
        
        lines = content.split('\n')
        
        bader_charges = []
        bader_volumes = []
        
        # 查找 Bader 分析表格
        # critic2 输出格式示例：
        # # Atomic properties
        # # Id   Z   Name   Population   Volume
        #    1   8   O      9.2345       45.234
        #    2   1   H      0.3827       12.123
        
        in_bader_table = False
        saw_population_header = False
        bader_populations = []
        
        for i, line in enumerate(lines):
            # 仅在明确 "Atomic properties" 段落中启用该解析器，避免误匹配其它 BADER 文本段。
            if "Atomic properties" in line:
                in_bader_table = True
                saw_population_header = False
                continue
            
            if not in_bader_table:
                continue
            
            # 跳过表头行
            if "Id" in line and "Population" in line:
                saw_population_header = True
                continue
            if not saw_population_header:
                continue
            
            # 尝试解析数据行
            parts = line.split()
            if len(parts) >= 5:
                try:
                    # 尝试解析数字
                    atom_id = int(parts[0])
                    z = int(parts[1])
                    name = parts[2]
                    population = float(parts[3])
                    volume = float(parts[4])
                    
                    # Bader 电荷 = Z - Population
                    charge = z - population
                    
                    bader_charges.append(charge)
                    bader_populations.append(population)
                    bader_volumes.append(volume)
                    
                except (ValueError, IndexError):
                    # 不是数据行
                    if len(bader_charges) > 0:
                        # 已经解析了一些数据，遇到非数据行表示结束
                        break
                    continue
            elif len(bader_charges) > 0 and line.strip() == "":
                # 空行表示表格结束
                break
        
        if bader_charges:
            features["qtaim"]["bader_charges"] = bader_charges
            features["qtaim"]["bader_populations"] = bader_populations
            features["qtaim"]["bader_volumes"] = bader_volumes
            features["qtaim"]["n_bader_volumes"] = len(bader_volumes)
            features["qtaim"]["atomic_integrated_properties"] = {
                "Population": [float(x) for x in bader_populations],
                "Volume": [float(x) for x in bader_volumes],
            }
            features["qtaim"]["metadata"].update(
                {
                    "atomic_property_parser": "atomic_properties_table_v1",
                    "atomic_property_source": "Atomic properties",
                    "atomic_property_header_tokens": ["Id", "Z", "Name", "Population", "Volume"],
                    "atomic_property_header_token_count": 5,
                    "atomic_property_rows_parsed": len(bader_charges),
                    "atomic_property_pop_column": "Population",
                    "atomic_property_volume_column": "Volume",
                    "atomic_property_volume_available": True,
                    "atomic_property_parse_note": "parsed_from_atomic_properties_table",
                    "atomic_integrated_property_columns": ["Population", "Volume"],
                }
            )
            logger.info(f"Parsed {len(bader_charges)} Bader volumes")
        else:
            # Fallback parser for "Integrated atomic properties" table (YT/BADER outputs)
            charges2, populations2, volumes2, parse_meta, integrated_properties = self._parse_integrated_atomic_properties(content)
            features["qtaim"]["metadata"].update(parse_meta)
            if isinstance(integrated_properties, dict) and integrated_properties:
                features["qtaim"]["atomic_integrated_properties"] = integrated_properties
            if charges2:
                features["qtaim"]["bader_charges"] = charges2
                features["qtaim"]["bader_populations"] = populations2
                features["qtaim"]["bader_volumes"] = volumes2
                features["qtaim"]["n_bader_volumes"] = len(volumes2) if isinstance(volumes2, list) else 0
                logger.info(f"Parsed {len(charges2)} atomic properties from integrated table")
            else:
                logger.warning("No Bader data found in output")
        
        return features

    @staticmethod
    def _normalize_column_name(token: str) -> str:
        """Normalize critic2 header token for robust column matching."""
        return re.sub(r"[^a-z0-9]+", "", token.lower())

    @staticmethod
    def _pick_column_index(raw_tokens: List[str], normalized_tokens: List[str], candidates: List[str]) -> Optional[int]:
        """Pick a column index by exact, prefix, then contains matching."""
        normalized_candidates = [Critic2Adapter._normalize_column_name(c) for c in candidates]
        for candidate in normalized_candidates:
            for idx, token in enumerate(normalized_tokens):
                if token == candidate:
                    return idx
        for candidate in normalized_candidates:
            for idx, token in enumerate(normalized_tokens):
                if token.startswith(candidate):
                    return idx
        for candidate in normalized_candidates:
            for idx, token in enumerate(normalized_tokens):
                if candidate and candidate in token:
                    return idx
        return None

    def _parse_integrated_atomic_properties(
        self, content: str
    ) -> tuple[List[float], List[float], Optional[List[Optional[float]]], Dict[str, Any], Optional[Dict[str, List[Optional[float]]]]]:
        """
        解析 Integrated atomic properties 表：
        # Id cp ncp Name Z mult <integrables...>

        NOTE:
        仅在识别到真正表头（"# Id ... mult ...") 时才会进行列映射，
        避免把其它 "#" 说明行错误当成表头导致列错位。
        """
        lines = content.split('\n')
        in_table = False
        header_tokens_raw: List[str] = []
        header_tokens_norm: List[str] = []
        charges: List[float] = []
        populations: List[float] = []
        volumes: List[Optional[float]] = []
        table_excerpt: List[str] = []
        pop_idx: Optional[int] = None
        vol_idx: Optional[int] = None
        z_idx: Optional[int] = None
        mult_idx: Optional[int] = None
        property_columns: List[str] = []
        property_indices: List[int] = []
        property_values: Dict[str, List[Optional[float]]] = {}
        parse_note = "integrated_atomic_properties_not_found"
        source = "Integrated atomic properties"

        for line in lines:
            if "Integrated atomic properties" in line:
                in_table = True
                parse_note = "integrated_atomic_properties_found"
                if len(table_excerpt) < 12:
                    table_excerpt.append(line.rstrip())
                continue
            if not in_table:
                continue

            s = line.strip()
            if len(table_excerpt) < 12:
                table_excerpt.append(line.rstrip())

            if not s:
                if charges:
                    break
                continue
            if s.startswith("* Integrated molecular properties") or s.startswith("critic2:"):
                break
            if s.startswith("#"):
                # Only accept the canonical table header.
                if re.match(r"^#\s*Id\b", s, flags=re.IGNORECASE):
                    header_tokens_raw = s.lstrip("#").split()
                    header_tokens_norm = [self._normalize_column_name(tok) for tok in header_tokens_raw]
                    z_idx = self._pick_column_index(header_tokens_raw, header_tokens_norm, ["Z"])
                    pop_idx = self._pick_column_index(
                        header_tokens_raw,
                        header_tokens_norm,
                        ["Pop", "Population", "ElectronPopulation", "ElectronPop"],
                    )
                    vol_idx = self._pick_column_index(
                        header_tokens_raw,
                        header_tokens_norm,
                        ["Volume", "Vol"],
                    )
                    mult_idx = self._pick_column_index(
                        header_tokens_raw,
                        header_tokens_norm,
                        ["mult"],
                    )
                    property_columns = []
                    property_indices = []
                    property_values = {}
                    if mult_idx is not None:
                        for idx in range(mult_idx + 1, len(header_tokens_raw)):
                            col = header_tokens_raw[idx]
                            property_columns.append(col)
                            property_indices.append(idx)
                            property_values[col] = []
                    if pop_idx is None:
                        parse_note = "integrated_header_found_but_pop_column_missing"
                    else:
                        parse_note = "integrated_header_found"
                continue
            if set(s) == {"-"}:
                continue

            parts = s.split()
            if not parts or not parts[0].isdigit():
                continue
            if pop_idx is None:
                continue
            try:
                if z_idx is None or z_idx >= len(parts) or pop_idx >= len(parts):
                    continue

                z = int(parts[z_idx])
                pop = float(parts[pop_idx])
                volume = None
                if vol_idx is not None and vol_idx < len(parts):
                    volume = float(parts[vol_idx])
            except (ValueError, IndexError):
                continue

            charges.append(float(z - pop))
            populations.append(float(pop))
            volumes.append(volume)
            for col, col_idx in zip(property_columns, property_indices):
                val: Optional[float] = None
                if col_idx < len(parts):
                    try:
                        val = float(parts[col_idx])
                    except (ValueError, TypeError):
                        val = None
                property_values[col].append(val)

        if populations and pop_idx is not None:
            parse_note = "integrated_atomic_properties_parsed"

        volume_values: Optional[List[Optional[float]]] = volumes if vol_idx is not None else None
        if vol_idx is None and populations:
            parse_note = "integrated_atomic_properties_parsed_without_volume_column"

        # Keep only meaningful columns (at least one numeric value parsed).
        cleaned_property_values: Dict[str, List[Optional[float]]] = {}
        for col, vals in property_values.items():
            if any(v is not None for v in vals):
                cleaned_property_values[col] = vals

        parse_meta: Dict[str, Any] = {
            "atomic_property_parser": "integrated_atomic_properties_v2",
            "atomic_property_source": source,
            "atomic_property_header_tokens": header_tokens_raw or None,
            "atomic_property_header_token_count": len(header_tokens_raw),
            "atomic_property_rows_parsed": len(populations),
            "atomic_property_pop_column": header_tokens_raw[pop_idx] if (pop_idx is not None and pop_idx < len(header_tokens_raw)) else None,
            "atomic_property_volume_column": header_tokens_raw[vol_idx] if (vol_idx is not None and vol_idx < len(header_tokens_raw)) else None,
            "atomic_property_volume_available": vol_idx is not None,
            "atomic_property_parse_note": parse_note,
            "atomic_property_table_excerpt": table_excerpt,
            "atomic_integrated_property_columns": list(cleaned_property_values.keys()) if cleaned_property_values else None,
        }

        return charges, populations, volume_values, parse_meta, (cleaned_property_values or None)
    
    def _parse_version(self, content: str) -> Optional[str]:
        """解析 critic2 版本"""
        # 查找版本信息行
        for line in content.split('\n'):
            if "critic2" in line.lower() and "version" in line.lower():
                # 尝试提取版本号
                parts = line.split()
                for i, part in enumerate(parts):
                    if "version" in part.lower() and i + 1 < len(parts):
                        return parts[i + 1]
        return None
    
    def _extract_warnings(self, content: str) -> List[str]:
        """提取警告信息"""
        warnings = []
        for line in content.split('\n'):
            if "warning" in line.lower():
                warnings.append(line.strip())
        return warnings


def run_critic2_analysis(
    context: BridgeContext,
    config: Optional[Dict[str, Any]] = None
) -> ExternalResult:
    """
    便捷函数：运行 critic2 分析
    
    Args:
        context: 桥接上下文
        config: 可选配置
        
    Returns:
        ExternalResult
    """
    adapter = Critic2Adapter(config)
    return adapter.execute(context)
